#include<cstdio>
#include<vector>
#include<set>
#include<map>
#include<cstdlib>
#include<cstring>
using namespace std;int W,H,turn;bool wall[99][99];struct N{int x,y,dx,dy;};vector<N>nodes;vector<int>prev_x,prev_y;struct B{int x,y,t;};vector<B>bombs;N mv(N n){if(!n.dx&&!n.dy)return n;int nx=n.x+n.dx,ny=n.y+n.dy;if(nx<0||nx>=W||ny<0||ny>=H||wall[ny][nx]){n.dx=-n.dx;n.dy=-n.dy;nx=n.x+n.dx;ny=n.y+n.dy;}n.x=nx;n.y=ny;return n;}vector<N>sim(vector<N>ns,int t){for(int i=0;i<t;i++)for(auto&n:ns)n=mv(n);return ns;}set<int>blast(int bx,int by){set<int>r;r.insert(by*W+bx);int dx[]={0,0,1,-1},dy[]={1,-1,0,0};for(int d=0;d<4;d++)for(int i=1;i<=3;i++){int cx=bx+dx[d]*i,cy=by+dy[d]*i;if(cx<0||cx>=W||cy<0||cy>=H||wall[cy][cx])break;r.insert(cy*W+cx);}return r;}int main(){scanf("%d%d",&W,&H);char grid[99][99];for(;;){int rl,ba;scanf("%d%d",&rl,&ba);vector<pair<int,int>>cur;for(int y=0;y<H;y++){scanf("%s",grid[y]);for(int x=0;x<W;x++){if(!turn&&grid[y][x]=='#')wall[y][x]=1;if(grid[y][x]=='@')cur.push_back({x,y});}}if(!turn){nodes.clear();for(auto[x,y]:cur)nodes.push_back({x,y,0,0});prev_x.clear();prev_y.clear();for(auto[x,y]:cur){prev_x.push_back(x);prev_y.push_back(y);}}else if(turn==1){set<int>used;vector<N>nn;for(int j=0;j<(int)prev_x.size();j++){int best=-1,bd=99;for(int i=0;i<(int)cur.size();i++){if(used.count(i))continue;int d=abs(cur[i].first-prev_x[j])+abs(cur[i].second-prev_y[j]);if(d<bd){bd=d;best=i;}}if(best>=0&&bd<=1){used.insert(best);nn.push_back({cur[best].first,cur[best].second,cur[best].first-prev_x[j],cur[best].second-prev_y[j]});}}for(int i=0;i<(int)cur.size();i++)if(!used.count(i))nn.push_back({cur[i].first,cur[i].second,0,0});nodes=nn;}else{map<int,pair<int,int>>um;for(auto[x,y]:cur)um[y*W+x]={x,y};vector<N>nn;for(auto n:nodes){auto m=mv(n);int k=m.y*W+m.x;if(um.count(k)){nn.push_back(m);um.erase(k);}}for(auto[_,p]:um)nn.push_back({p.first,p.second,0,0});nodes=nn;}for(auto&b:bombs)b.t--;bool ch=1;while(ch){ch=0;for(int i=bombs.size()-1;i>=0;i--)if(bombs[i].t<=0){auto cells=blast(bombs[i].x,bombs[i].y);bombs.erase(bombs.begin()+i);vector<N>nn;for(auto&n:nodes)if(!cells.count(n.y*W+n.x))nn.push_back(n);nodes=nn;for(auto&b:bombs)if(cells.count(b.y*W+b.x))b.t=0;ch=1;}}if(!ba||nodes.empty()||!turn){puts("WAIT");fflush(stdout);prev_x.clear();prev_y.clear();for(auto[x,y]:cur){prev_x.push_back(x);prev_y.push_back(y);}turn++;continue;}int mw=min(rl-4,55),bw=-1,bx=-1,by=-1,bh=0;for(int w=0;w<=mw;w++){auto ab=sim(nodes,w+3);auto ap=w?sim(nodes,w):vector<N>{};map<int,int>cs;for(auto&n:ab)for(int c:blast(n.x,n.y))cs[c]++;set<int>ps;if(w)for(auto&n:ap)ps.insert(n.y*W+n.x);for(auto[c,h]:cs){if(h<=bh)continue;int x=c%W,y=c/W;if(wall[y][x])continue;if(!w&&grid[y][x]!='.')continue;if(w&&ps.count(c))continue;if([&]{for(auto&b:bombs)if(b.x==x&&b.y==y)return 1;return 0;}())continue;bh=h;bw=w;bx=x;by=y;}if(bh>=(int)nodes.size())break;}if(!bw&&bh>0){bombs.push_back({bx,by,3});printf("%d %d\n",bx,by);}else puts("WAIT");fflush(stdout);turn++;}}